arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    static ZipCreator()
    {
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
    }

    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now sets the UTF-8 flag by default,
        // which breaks the legacy Java consumer that expects Shift-JIS.
        // Pass an explicit encoding to suppress the UTF-8 flag.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create,
            Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

